var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"행복에는 정해진 양이 있어요.","JPN":"幸せには決められた量があります。","ENG":"There is a finite amount to happiness.","TWN":"幸福是有限的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"모두가 행복한 세상은 꿈 같은 소리죠.","JPN":"みんなが幸せな世の中なんて、夢のような話です。","ENG":"A world where everyone can be happy is the stuff of fairy tales.","TWN":"所有人都很幸福的理想世界，只存在於夢裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"배부른 사람이 있으면 배고픈 사람이 있고, 오래 사는 사람이 있으면 태어나지도 못하고 죽는 사람이 있는 것처럼.","JPN":"満腹の人がいれば空腹の人がいて、長生きする人がいれば生まれることもできずに死ぬ人がいるように。","ENG":"While some go well-fed, there are those who go hungry. Some live long, fulfilling lives, while others perish before they draw their first breath.","TWN":"就好像有不愁吃喝的也有挨餓受凍的，有活得久的也有還沒出生就已經死去的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 자기가 행복하다는 사실을 알려면 어떻게 해야 될까요?","JPN":"それでは、自分が幸せだという事実を知るにはどうすれば良いのでしょうか？","ENG":"Then how can you tell if you're happy?","TWN":"那怎麼才能知道自己是幸福的呢？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"간단해요. 다른 사람이 고통 속에서 몸부림치는 모습을 보면 되죠.","JPN":"簡単です。他の人が苦しみ悶える姿を見ればいいのです。","ENG":"It's simple. All you need to do is see someone else writhing in agony.","TWN":"很簡單，當看到別人深陷於痛苦之中，你就懂了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"굶주림에, 질병에, 혹은 아픔에 못 이겨 울부짖는 모습을 감상하고 있노라면......","JPN":"飢えや病気、あるいは痛みに耐え切れず泣き叫ぶ姿を見ていると……","ENG":"As you gaze upon those who scream from hunger, disease, or pain...","TWN":"欣賞著人們因饑餓、疾病，或者因痛苦而哀嚎……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"자기가 얼마나 행복에 겨운지, 얼마나 우월한 위치에 서 있는지 실감할 수 있거든요.","JPN":"自分がどれだけ幸せ者なのか、どれだけ優位な立場にいるのかを実感できるのです。","ENG":"You'll come to truly appreciate how happy you really are. How superior your life truly is.","TWN":"你就能知道自己有多幸福，處於多高的位置了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 사람들은 인형을 찾는 거예요.","JPN":"だから、人々は人形を求める。","ENG":"That is why people seek puppets.","TWN":"所以人們才要想找個木偶。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"자기 발 밑에 무릎 꿇은 채로 괴로워하고, 비명을 질러 줄......","JPN":"自分の足元に跪き、苦しんで悲鳴を上げてくれる……","ENG":"Lovely puppets...","TWN":"那種臣服於自己的腳下，痛苦掙扎並哀嚎的……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"......사랑스러운 인형을.","JPN":"……可愛らしい人形を。","ENG":"that would scream and kneel in agony at their feet.","TWN":"……可愛的傀儡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"그거 참...... 이해하기 어려운 이야기네요.","JPN":"それはちょっと……理解できない話ですね。","ENG":"Well... I must say that's a lot to take in.","TWN":"你的話……真是讓人難以理解。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 괜찮아요. 제 얘기를 들으면 다들 당신처럼 반응하니까요.","JPN":"ふふっ、いいんです。\\n私の話を聞いた人はみんなあなたのような反応をしますから。","ENG":"Hah hah. That's alright. Everyone responds the same way.","TWN":"哈哈，沒關係，很多人聽到我的話都跟你一樣的反應。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"크흠, 흠. 물론 그렇겠죠.","JPN":"こほん、ふむ。誰だってそうでしょう。","ENG":"Kahem, hem. I suppose they would.","TWN":"咳咳，咳。我想也是。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"그러니 이제 그만 질문에 대답해 주시면 좋겠습니다. 하랍 크로넨워스 씨.","JPN":"では、そろそろ質問にお答えいただきたいのですが。ハーラヴ・クロネンワースさん。","ENG":"Well, then. Would you please answer my question now, Miss Harab Cronenworth?","TWN":"好了，現在請你回答我的問題。哈拉普·克羅尼溫斯。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"저희 도시를 방문하는 목적이 무엇입니까?","JPN":"この都市を訪問される目的は何ですか？","ENG":"What is the purpose of your visit to our city?","TWN":"你來我們城市的目的是什麼？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"할로윈 페스티벌에 초청 받았어요. 퍼레이드 공연팀을 데리고 왔거든요.","JPN":"ハロウィンフェスティバルに招待されました。パレード公演チームを連れてきているんです。","ENG":"I've been invited to the Halloween festival. I brought a team to perform at the parade.","TWN":"我受邀參加萬聖節慶典，我還帶來了遊行表演團隊。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MALE_NPC_POLICE_NULL","text":{"KOREA":"퍼레이드요?","JPN":"パレードですか？","ENG":"The parade?","TWN":"遊行表演？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MALE_NPC_POLICE_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};